    controller->settling_started_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    /* Check for sensor timeout or malformed input - go to safe state */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT ||
        input.kind == CONTROLLER_INPUT_INVALID_TURBIDITY ||
        input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        controller_set_safe_idle(controller);
        output.timed_out = true;
        return output;
    }

    /* Check for no input - stay in safe state */
    if (input.kind == CONTROLLER_INPUT_NONE) {
        /* No action needed - just check if we're already in a complete state with level < 15 */
        if (controller->state == CONTROLLER_STATE_COMPLETE && controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
            output.filter_on = false;
            output.drain_open = false;
            output.state = CONTROLLER_STATE_COMPLETE;
            output.state_name = controller_state_name(CONTROLLER_STATE_COMPLETE);
            output.changed = (previous_filter_on != output.filter_on) ||
                             (previous_drain_open != output.drain_open) ||
                             (previous_state != output.state);
        } else {
            /* Stay in safe idle, no change */
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = false;
        }
        return output;
    }

    /* Process TURBIDITY input */
    if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
        /* Check sensor timeout - if more than 1000ms since last valid turbidity, go safe */
        if (controller->last_turbidity_ms > 0U &&
            (input.now_ms - controller->last_turbidity_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
            /* Sensor timeout detected */
            controller_set_safe_idle(controller);
            output.timed_out = true;
            return output;
        }

        /* Check if this is a valid turbidity value (0-100) */
        if (input.turbidity_ntu < 0 || input.turbidity_ntu > 100) {
            controller->has_valid_turbidity = false;
            controller_set_safe_idle(controller);
            output.timed_out = true;
            return output;
        }

        /* Update turbidity state */
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = input.now_ms;

        /* Check level timeout - if more than 1000ms since last valid level, go safe */
        if (controller->has_valid_level &&
            (input.now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
            controller_set_safe_idle(controller);
            output.timed_out = true;
            return output;
        }

        /* Process based on current state and conditions */
        switch (controller->state) {
        case CONTROLLER_STATE_SAFE_IDLE:
            /* Stay in safe idle until both sensors have valid data */
            break;

        case CONTROLLER_STATE_FILTERING:
            /* Turbidity > 35 resets clear streak, otherwise increment */
            if (input.turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                controller->clear_streak_count = 0;
            } else {
                controller->clear_streak_count++;
            }
            /* Stay in FILTERING state */
            break;

        case CONTROLLER_STATE_SETTLING:
            /* TURB > 40 resets streak and returns to FILTERING */
            if (input.turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
                controller->clear_streak_count = 0;
                output.filter_on = true;
                output.drain_open = false;
                output.state = CONTROLLER_STATE_FILTERING;
                output.state_name = controller_state_name(CONTROLLER_STATE_FILTERING);
                output.changed = (previous_filter_on != output.filter_on) ||
                                 (previous_drain_open != output.drain_open) ||
                                 (previous_state != output.state);
            } else {
                /* Stay in SETTLING */
                break;
            }
            break;

        case CONTROLLER_STATE_DRAINING:
            /* TURB > 50 and LEVEL >= 40 closes drain, turns filter on, resets streak, returns to FILTERING */
            if (input.turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU &&
                controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                controller->clear_streak_count = 0;
                output.filter_on = true;
                output.drain_open = false;
                output.state = CONTROLLER_STATE_FILTERING;
                output.state_name = controller_state_name(CONTROLLER_STATE_FILTERING);
                output.changed = (previous_filter_on != output.filter_on) ||
                                 (previous_drain_open != output.drain_open) ||
                                 (previous_state != output.state);
            } else {
                /* Stay in DRAINING */
                break;
            }
            break;

        case CONTROLLER_STATE_COMPLETE:
            /* Already complete, stay there */
            break;
        }

        output.filter_on = controller->filter_on;
        output.drain_open = controller->drain_open;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed = (previous_filter_on != output.filter_on) ||
                         (previous_drain_open != output.drain_open) ||
                         (previous_state != output.state);
        return output;
    }

    /* Process LEVEL input */
    if (input.kind == CONTROLLER_INPUT_LEVEL) {
        /* Check sensor timeout - if more than 1000ms since last valid turbidity, go safe */
        if (controller->has_valid_turbidity &&
            (input.now_ms - controller->last_turbidity_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
            controller_set_safe_idle(controller);
            output.timed_out = true;
            return output;
        }

        /* Check if this is a valid level value (0-100) */
        if (input.level < 0 || input.level > 100) {
            controller->has_valid_level = false;
            controller_set_safe_idle(controller);
            output.timed_out = true;
            return output;
        }

        /* Update level state */
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;

        /* Check if both sensors now have valid data - leave safe idle */
        if (controller->state == CONTROLLER_STATE_SAFE_IDLE &&
            controller->has_valid_turbidity &&
            controller->has_valid_level) {
            /* Both sensors valid, now check level condition */
            if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
                /* Level below threshold - stay COMPLETE with filter off and drain closed */
                output.filter_on = false;
                output.drain_open = false;
                output.state = CONTROLLER_STATE_COMPLETE;
                output.state_name = controller_state_name(CONTROLLER_STATE_COMPLETE);
                output.changed = (previous_filter_on != output.filter_on) ||
                                 (previous_drain_open != output.drain_open) ||
                                 (previous_state != output.state);
            } else {
                /* Level >= 40, check turbidity to determine next state */
                if (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU &&
                    controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                    /* TURB > 35 and LEVEL >= 40 - start filtering */
                    controller->clear_streak_count = 0;
                    output.filter_on = true;
                    output.drain_open = false;
                    output.state = CONTROLLER_STATE_FILTERING;
                    output.state_name = controller_state_name(CONTROLLER_STATE_FILTERING);
                    output.changed = (previous_filter_on != output.filter_on) ||
                                     (previous_drain_open != output.drain_open) ||
                                     (previous_state != output.state);
                } else {
                    /* TURB <= 35 and LEVEL >= 40 - stay in safe idle, waiting for more data */
                    output.filter_on = false;
                    output.drain_open = false;
                    output.state = CONTROLLER_STATE_SAFE_IDLE;
                    output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE);
                    output.changed = (previous_filter_on != output.filter_on) ||
                                     (previous_drain_open != output.drain_open) ||
                                     (previous_state != output.state);
                }
            }
        } else {
            /* Not both sensors valid yet - stay in safe idle */
            if (controller->state == CONTROLLER_STATE_SAFE_IDLE) {
                output.filter_on = false;
                output.drain_open = false;
                output.state = CONTROLLER_STATE_SAFE_IDLE;
                output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE);
                output.changed = (previous_filter_on != output.filter_on) ||
                                 (previous_drain_open != output.drain_open) ||
                                 (previous_state != output.state);
            } else {
                /* Already in a non-safe state, stay there */
                output.filter_on = controller->filter_on;
                output.drain_open = controller->drain_open;
                output.state = controller->state;
                output.state_name = controller_state_name(controller->state);
                output.changed = false;
            }
        }
        return output;
    }

    /* Default case - should not reach here */
    controller_set_safe_idle(controller);
    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_filter_on != output.filter_on) ||
                     (previous_drain_open != output.drain_open) ||
                     (previous_state != output.state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

